const source = $input.first().json || {};
const payload = source.body || source;

function clean(value) {
  return value === undefined || value === null ? "" : String(value).trim();
}

function escapeHtml(value) {
  return String(value || "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/\"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

const taskId = clean(payload.task_id || payload.taskId || payload.task_reference || payload.reference_id);
const clientEmail = clean(payload.client_email || payload.email || payload.to).toLowerCase();
const clientName = clean(payload.client_name || payload.name) || "there";
const quoteAmount = clean(payload.quote_amount);
const deliveryEta = clean(payload.delivery_eta);
const quoteNote = clean(payload.quote_note || payload.note || payload.scope);
const paymentLink = clean(payload.payment_link);
const secureReviewUrl = clean(payload.secure_review_url || payload.client_review_url || payload.review_url);
const sourceLabel = clean(payload.source) || "admin_quote";
const ctaUrl = clean(payload.cta_url || payload.primary_cta_url) || secureReviewUrl || paymentLink;
const subject = "DONEOVERNIGHT — Quote ready";

const html = clean(payload.html) || `
  <!doctype html>
  <html>
    <body style="margin:0;padding:0;background:#050608;color:#f5f1ea;font-family:Inter,Arial,sans-serif">
      <main style="max-width:560px;margin:0 auto;padding:44px 24px">
        <section style="border:1px solid rgba(233,196,138,.22);border-radius:8px;background:rgba(245,241,234,.035);padding:32px 28px">
          <p style="margin:0 0 24px;color:#e9c48a;font-size:11px;font-weight:800;letter-spacing:.2em;text-transform:uppercase">DONEOVERNIGHT</p>
          <h1 style="margin:0 0 18px;color:#f5f1ea;font-family:Georgia,'Times New Roman',serif;font-size:32px;line-height:1.12;font-weight:400">Quote ready.</h1>
          <p style="margin:0 0 22px;color:rgba(245,241,234,.78);font-size:15px;line-height:1.7">Hi ${escapeHtml(clientName)}, your DONEOVERNIGHT quote is ready for approval and payment.</p>
          <table role="presentation" width="100%" cellspacing="0" cellpadding="0" style="margin:22px 0;border-top:1px solid rgba(245,241,234,.12);border-bottom:1px solid rgba(245,241,234,.12)">
            <tr><td style="padding:8px 0;color:rgba(245,241,234,.54);font-size:12px;letter-spacing:.12em;text-transform:uppercase">Reference</td><td style="padding:8px 0;color:#f5f1ea;font-size:14px;text-align:right">${escapeHtml(taskId)}</td></tr>
            <tr><td style="padding:8px 0;color:rgba(245,241,234,.54);font-size:12px;letter-spacing:.12em;text-transform:uppercase">Quote</td><td style="padding:8px 0;color:#f5f1ea;font-size:14px;text-align:right">${escapeHtml(quoteAmount)}</td></tr>
            <tr><td style="padding:8px 0;color:rgba(245,241,234,.54);font-size:12px;letter-spacing:.12em;text-transform:uppercase">Delivery ETA</td><td style="padding:8px 0;color:#f5f1ea;font-size:14px;text-align:right">${escapeHtml(deliveryEta)}</td></tr>
          </table>
          ${quoteNote ? `<div style="margin:0 0 22px;padding:16px 18px;border:1px solid rgba(245,241,234,.12);border-radius:6px;background:rgba(0,0,0,.18)"><p style="margin:0 0 8px;color:rgba(245,241,234,.52);font-size:11px;letter-spacing:.14em;text-transform:uppercase">Scope note</p><p style="margin:0;color:#f5f1ea;font-size:15px;line-height:1.65">${escapeHtml(quoteNote)}</p></div>` : ""}
          ${ctaUrl ? `<p style="margin:0 0 14px"><a href="${escapeHtml(ctaUrl)}" style="display:inline-block;padding:13px 18px;border:1px solid rgba(233,196,138,.44);border-radius:999px;background:rgba(233,196,138,.08);color:#e9c48a;text-decoration:none;font-size:11px;font-weight:800;letter-spacing:.14em;text-transform:uppercase">Approve &amp; Pay</a></p>` : ""}
          ${paymentLink ? `<p style="margin:0 0 24px;color:rgba(245,241,234,.7);font-size:13px;line-height:1.7">Payment link fallback:<br><a href="${escapeHtml(paymentLink)}" style="color:#e9c48a;text-decoration:underline;text-underline-offset:4px">${escapeHtml(paymentLink)}</a></p>` : ""}
          <p style="margin:0;color:rgba(245,241,234,.58);font-size:13px;line-height:1.7">Workspace access opens after payment is confirmed.</p>
        </section>
      </main>
    </body>
  </html>
`;

const text = clean(payload.text) || [
  "DONEOVERNIGHT",
  "",
  `Hi ${clientName},`,
  "",
  "Quote ready.",
  `Reference: ${taskId}`,
  quoteAmount ? `Quote: ${quoteAmount}` : null,
  deliveryEta ? `Delivery ETA: ${deliveryEta}` : null,
  quoteNote ? `Scope: ${quoteNote}` : null,
  ctaUrl ? `Approve & Pay: ${ctaUrl}` : null,
  paymentLink ? `Payment link: ${paymentLink}` : null,
  "",
  "Workspace access opens after payment is confirmed.",
  "",
  "DONEOVERNIGHT"
].filter(Boolean).join("\n");

return [{
  json: {
    task_id: taskId,
    client_email: clientEmail,
    client_name: clientName,
    quote_amount: quoteAmount,
    delivery_eta: deliveryEta,
    quote_note: quoteNote,
    payment_link: paymentLink,
    secure_review_url: secureReviewUrl,
    source: sourceLabel,
    cta_url: ctaUrl,
    subject,
    html,
    text,
    should_send: Boolean(clientEmail && clientEmail.includes("@")),
    provider: "n8n_outlook"
  }
}];
